{"query":"query getUser($userId: ID!) {
  user(id: $userId) {
    ...userBasicFields
  }
}

fragment userBasicFields on User {
  _id
  name
  phoneNumber
  jobTitle
  image
  displayEditorName
  email
  navigationTour
  liveblogTour
  chatTour
  isAdmin
  accounts {
    ...accountBasicFields
  }
  permissions {
    ...userPermissionFields
  }
  currentAccount {
    accountId
    organizationId
    siteId
  }
}

fragment accountBasicFields on Account {
  _id
  nam

